const std = @import("std");

fn binary_search(xs: []const i64, target: i64) i64 {
    var lo: i64 = 0;
    var hi: i64 = @as(i64, @intCast(xs.len)) - 1;
    while (lo <= hi) {
        const mid: i64 = @divTrunc(lo + hi, 2);
        if (xs[@intCast(mid)] == target) {
            return mid;
        }
        if (xs[@intCast(mid)] < target) {
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return -1;
}

pub fn main() void {
    var _xs_arr = [_]i64{1, 3, 5, 7, 9, 11, 13, 15};
    const xs: []i64 = _xs_arr[0..];
    std.debug.print("{} {}\n", .{ binary_search(xs, 7), binary_search(xs, 8) });
}
