fn bubble_sort(xs: []i64) i64 {
    const n: i64 = @as(i64, @intCast(xs.len));
    var swaps: i64 = 0;
    var i: i64 = 0;
    while (i < n) {
        var j: i64 = 0;
        while (j < n - i - 1) {
            if (xs[@intCast(j)] > xs[@intCast(j + 1)]) {
                const tmp: i64 = xs[@intCast(j)];
                xs[@intCast(j)] = xs[@intCast(j + 1)];
                xs[@intCast(j + 1)] = tmp;
                swaps += 1;
            }
            j += 1;
        }
        i += 1;
    }
    return swaps;
}

pub fn main() void {
    var _xs_arr = [_]i64{5, 3, 8, 1, 4};
    const xs: []i64 = _xs_arr[0..];
    std.debug.print("{}\n", .{ bubble_sort(xs) });
