const std = @import("std");

fn collatz_length(n_: i64) i64 {
    var n: i64 = n_;
    var steps: i64 = 0;
    while (n != 1) {
        if (@rem(n, 2) == 0) {
            n = @divTrunc(n, 2);
        } else {
            n = 3 * n + 1;
        }
        steps += 1;
    }
    return steps;
}

fn max_collatz_under(limit: i64) i64 {
    var best: i64 = 0;
    var i: i64 = 1;
    while (i < limit) {
        const c: i64 = collatz_length(i);
        if (c > best) {
            best = c;
        }
        i += 1;
    }
    return best;
}

