fn find_first(xs: []const i64, target: i64) i64 {
    var i: i64 = 0;
    while (i < @as(i64, @intCast(xs.len))) {
        if (xs[@intCast(i)] == target) {
            return i;
        }
        i += 1;
    }
    return -1;
}

fn count_occurrences(xs: []const i64, target: i64) i64 {
    var count: i64 = 0;
    var i: i64 = 0;
    while (i < @as(i64, @intCast(xs.len))) {
        if (xs[@intCast(i)] == target) {
            count += 1;
        }
        i += 1;
    }
    return count;
}

