const std = @import("std");

fn mandelbrot_iters(cx: f64, cy: f64, max_iter: i64) i64 {
    var x: f64 = 0.0;
    var y: f64 = 0.0;
    var i: i64 = 0;
    while (i < max_iter) {
        const x2: f64 = x * x;
        const y2: f64 = y * y;
        if (x2 + y2 > 4.0) {
            return i;
        }
        y = 2.0 * x * y + cy;
        x = x2 - y2 + cx;
        i += 1;
    }
    return max_iter;
}

fn in_mandelbrot(cx: f64, cy: f64) bool {
    return mandelbrot_iters(cx, cy, 100) == 100;
}

pub fn main() void {
    std.debug.print("{}\n", .{ mandelbrot_iters(0.0, 0.0, 100) });
    std.debug.print("{s}\n", .{ if (in_mandelbrot(0.5, 0.5)) "True" else "False" });
}
