const std = @import("std");

fn sum_list(xs: []const i64) i64 {
    var total: i64 = 0;
    var i: i64 = 0;
    while (i < @as(i64, @intCast(xs.len))) {
        total += xs[@intCast(i)];
        i += 1;
    }
    return total;
}

fn max_element(xs: []const i64) i64 {
    var best: i64 = xs[@intCast(0)];
    var i: i64 = 0;
    while (i < @as(i64, @intCast(xs.len))) {
        if (xs[@intCast(i)] > best) {
            best = xs[@intCast(i)];
        }
        i += 1;
    }
    return best;
}

